import{A as e}from"./assets.53fab6f9.js";import{g as a}from"./skills.c8a4a1c0.js";const r=[{slug:"sistema-sidaii",color:"#750C7D",description:"Sistema que fue realizado en colaboracion con el equipo de tecnologia de la Fundacion Mision Jose Gregorio Hernandez, se trata de un sistema que usan los trabajadores de la Fundacion Mision Jose Gregorio Hernandez, el cual se encarga de registrar a las personas que poseen una discapacidad que necesitan una ayuda tecnica (silla de ruedas, muletas, andaderas, artificios),el sistema se usa a nivel nacional en los 23 estados del pais de Venezuela,  posee roles de usuario, ademas de que cada usuario esta asignado a un estado del pais, da graficas, reportes, estados de las solicitudes, el historial de la persona, designar el caso a otra gerencia etc. Posee diferentes modulos para cada gerencia con las funciones especificas para cada una de las gerencias las cuales necesitan. ",shortDescription:"Sistema de registro y entrega de ayudas tecnicas para las personas con discapacidad a nivel nacional.",links:[],logo:e.PHP,name:"Sistema Sidaii",period:{from:new Date(2024,4,1),to:new Date(2026,0,14)},skills:a("php","css","js","html","Myadmin","Github"),type:"Website Template",screenshots:[{label:"1",src:"/proyectos/sidaii/sidaii_login.png"},{label:"2",src:"/proyectos/sidaii/sidaii_dashboard.png"}]},{slug:"intranet-recursos-humanos",color:"#D11313",description:"Junto con el equipo de tecnologia de la Fundacion Mision Jose Gregorio Hernandez, se construyo un sistema tipo intranet, el cual su funcion es informar a un trabajador individual sus reportes de pago, ademas de generarle una constancia de trabajo. Esto ayudo muchisimo, ya que anteriormente este proceso lo realizaba recursos humanos, ahora ,con este sistema , el trabajador tiene un usuario, el cual puede acceder al sistema mediante a un login. Puede cambiar sus credenciales, ademas de poder exportar a PDF sus reportes de pago del mes y tambien exportar a PDF su constancia de trabajo.",shortDescription:"Intranet la cual permite crear una constancia de trabajo y ver el reporte de ingresos que poseen los trabajadores.",links:[],logo:e.Laravel,name:"Intranet (Fundacion Jose Gregorio Hernandez)",period:{from:new Date(2025,1,20),to:new Date(2025,8,14)},skills:a("php","Laravel","Livewire","html","css","js","PostgreSQL","Github"),type:"Website Template",screenshots:[{label:"1",src:"/proyectos/intranet/presentacion_intranet.png"},{label:"2",src:"/proyectos/intranet/login_intranet.png"}]},{slug:"sistema-bienes",color:"#D11313",description:"Se logro desarrollar junto al equipo de tecnologia de la Fundacion Jose Gregorio Hernandez un sistema de inventario de sus bienes, estos son muletas, sillas de ruedas, baston, cama clinica, etc. El sistema se encarga de registrar el bien, para luego agregar la cantidad que se posee en el stock. Una vez hecho esto, si una persona o coordinacion necesita uno de los bienes de la Fundacion, en la seccion de retirar el stock, se procede realizar el proceso del retiro y se descuenta la cantidad del bien y se crea un comprobante en pdf del retiro. Se puede filtrar el historial de retiros por fechas, se tiene una tabla de la cantidad de bienes registrados ordenados por la cantidad de stock que poseen, es decir, el bien con mas stock del sistema es el que esta en la parte superior. El sistema luego se adapto para la organizacion Conapdis, el cual llevaba sus propios bienes.",shortDescription:"Sistema que se encarga de llevar un registro de los bienes para la Fundacion Jose Gregorio Hernandez.",links:[],logo:e.Laravel,name:"Sistema de bienes (Fundacion Jose Gregorio Hernandez)",period:{from:new Date(2025,1,25),to:new Date(2025,11,16)},skills:a("php","Laravel","Livewire","html","css","js","Myadmin","Github"),type:"Website Template",screenshots:[{label:"1",src:"/proyectos/bienes/login_bienes.png"},{label:"2",src:"/proyectos/bienes/dashboard_bienes.png"},{label:"3",src:"/proyectos/bienes/retiro_bien.png"}]},{slug:"clon-traductor-google",color:"#FFF700",description:"Desarrolle un proyecto en solitario del mitico traductor de Google, el cual se desarrollo con HTML, CSS y Javascript como frontend y de backend se uso nodeJS y express. Se separo por carpetas el frontend y el backend. El traductor posee las funciones principales del traductor, puede traducir el lenguaje que se ingresa, puedes invertir el idioma, la funcion del microfono funciona y se pone a texto lo que dijiste a traducir, tiene un limite de 5000 caracteres, puedes copiar y pegar la traduccion ademas de poseer el modo oscuro, una funcion novedosa por mi parte el cual no posee el traductor de Google. Posee su mismo icono en la pestaña del navegador, su misma tipografia, el mismo logo y ser lo mas fiel posible.",shortDescription:"Clon del traductor mas famoso de internet, puede escuchar audio de la traduccion, detectar idioma, etc. ",links:[{to:"https://github.com/Gerardo8943/Traductor-Google-clon-",label:"GitHub"}],logo:e.JavaScript,name:"Clon de traductor Google",period:{from:new Date(2025,9,9)},skills:a("html","css","js","NodeJs","ExpressJs","Github"),type:"Website Template",screenshots:[{label:"1",src:"/proyectos/google_traductor/presentacion.png"},{label:"2",src:"/proyectos/google_traductor/traduccion_ei.png"},{label:"3",src:"/proyectos/google_traductor/traduccion_ej.png"},{label:"4",src:"/proyectos/google_traductor/traductor_dark.png"}]}],i="Proyectos";export{r as i,i as t};
